function whatsappNumber(phone){let n=String(phone||"").replace(/\D/g,"");if(n.startsWith("0"))n=`94${n.slice(1)}`;return n}
function validWhatsAppInput(phone){const n=whatsappNumber(phone);return n.length>=11&&n.length<=15}
function studentWhatsAppPhone(student){return whatsappNumber(student?.guardian)||whatsappNumber(student?.phone)}
