function renderAnalytics(){
  const period=$("#analyticsPeriod").value,course=$("#analyticsCourse").value,bins=analyticsBins(period),matching=students.filter(s=>course==="all"||s.course===course),ids=new Set(matching.map(s=>s.id));
  const attendanceData=bins.map(bin=>{let present=0,total=0;Object.entries(attendance).forEach(([date,marks])=>{const actual=analyticsDateKey(date);if(actual<bin.start||actual>bin.end)return;Object.entries(marks).forEach(([id,value])=>{if(ids.has(id)&&(value==="present"||value==="absent")){total++;if(value==="present")present++}})});return{...bin,present,total,rate:total?Math.round(present/total*100):0}});
  const paymentData=bins.map(bin=>{const list=receipts.filter(r=>{const date=String(r.createdAt||"").slice(0,10);return date>=bin.start&&date<=bin.end&&(course==="all"||r.student.course===course)});return{...bin,value:list.reduce((sum,r)=>sum+Number(r.payment||0),0),count:list.length}});
  const totalPresent=attendanceData.reduce((n,x)=>n+x.present,0),totalMarks=attendanceData.reduce((n,x)=>n+x.total,0),totalCollection=paymentData.reduce((n,x)=>n+x.value,0),receiptCount=paymentData.reduce((n,x)=>n+x.count,0),periodStudents=students.filter(s=>s.joined>=bins[0].start&&s.joined<=bins.at(-1).end&&(course==="all"||s.course===course)),courseCounts=COURSES.map(name=>({name,count:periodStudents.filter(s=>s.course===name).length})),popular=[...courseCounts].sort((a,b)=>b.count-a.count)[0],paid=matching.filter(s=>paymentStatus(s)==="Paid").length,pending=matching.length-paid,paidRate=matching.length?Math.round(paid/matching.length*100):0,maxPayment=Math.max(1,...paymentData.map(x=>x.value)),maxCourse=Math.max(1,...courseCounts.map(x=>x.count));
  const lowStats=attendanceStats().filter(x=>(course==="all"||x.student.course===course)&&x.total>0&&x.rate<75),outstanding=matching.reduce((sum,s)=>sum+Math.max(0,s.fee-s.paid),0),avgReceipt=receiptCount?Math.round(totalCollection/receiptCount):0;
  const courseRevenue=COURSES.map(name=>({name,value:receipts.filter(r=>r.student.course===name).reduce((sum,r)=>sum+Number(r.payment||0),0)})),maxRevenue=Math.max(1,...courseRevenue.map(x=>x.value));
  const followups=[...matching].map(student=>{const stat=attendanceStats().find(x=>x.student.id===student.id)||{rate:0,total:0};return{student,rate:stat.total?stat.rate:null,due:Math.max(0,student.fee-student.paid)}}).filter(x=>x.due>0||(x.rate!==null&&x.rate<75)).sort((a,b)=>(b.due-a.due)||((a.rate??100)-(b.rate??100))).slice(0,5);
  $("#analyticsAttendanceRate").textContent=`${totalMarks?Math.round(totalPresent/totalMarks*100):0}%`;$("#analyticsAttendanceDetail").textContent=`${totalPresent} present of ${totalMarks} marks`;$("#analyticsCollection").textContent=money(totalCollection);$("#analyticsReceiptDetail").textContent=`${receiptCount} receipt${receiptCount===1?"":"s"} in selected period`;$("#analyticsPopular").textContent=popular?.count?popular.name:"No registrations";$("#analyticsPopularDetail").textContent=`${popular?.count||0} students joined`;$("#analyticsStudents").textContent=matching.length;$("#analyticsLowAttendance").textContent=lowStats.length;$("#analyticsOutstanding").textContent=money(outstanding);$("#analyticsOutstandingDetail").textContent=`${pending} pending student${pending===1?"":"s"}`;$("#analyticsNewStudents").textContent=periodStudents.length;$("#analyticsAvgReceipt").textContent=money(avgReceipt);
  $("#attendanceChartTitle").textContent=period==="weekly"?"Weekly attendance":"Monthly attendance";$("#paymentChartTitle").textContent=period==="weekly"?"Weekly payment collection":"Monthly payment collection";
  $("#attendanceChart").innerHTML=attendanceData.map(x=>`<div class="chart-column"><strong>${x.total?`${x.rate}%`:"—"}</strong><div class="chart-bar"><i style="height:${x.rate}%"></i></div><span>${x.label}</span></div>`).join("");
  $("#paymentChart").innerHTML=paymentData.map(x=>`<div class="chart-column"><strong>${x.value?money(x.value).replace("Rs. ",""):"—"}</strong><div class="chart-bar"><i style="height:${Math.round(x.value/maxPayment*100)}%"></i></div><span>${x.label}</span></div>`).join("");
  $("#courseChart").innerHTML=courseCounts.map(x=>`<div class="course-chart-row"><span>${esc(x.name)}</span><div class="course-chart-bar"><i style="width:${Math.round(x.count/maxCourse*100)}%"></i></div><strong>${x.count}</strong></div>`).join("");
  $("#paymentDonut").style.setProperty("--donut-rate",`${paidRate*3.6}deg`);$("#paymentDonutRate").textContent=`${paidRate}%`;$("#analyticsPaidStudents").textContent=paid;$("#analyticsPendingStudents").textContent=pending;
  $("#analyticsFollowup").innerHTML=followups.length?followups.map(x=>`<div class="analytics-followup-row">${studentCell(x.student)}<div><span>${x.rate===null?"No attendance":`${x.rate}% attendance`}</span><strong>${x.due?`${money(x.due)} due`:"Attendance follow-up"}</strong></div></div>`).join(""):`<div class="empty">No priority follow-ups</div>`;
  $("#analyticsCourseRevenue").innerHTML=courseRevenue.map(x=>`<div class="course-chart-row"><span>${esc(x.name)}</span><div class="course-chart-bar revenue-bar"><i style="width:${Math.round(x.value/maxRevenue*100)}%"></i></div><strong>${money(x.value).replace("Rs. ","")}</strong></div>`).join("");
  const arrears=arrearsStudents(course);$("#analyticsArrearsList").innerHTML=arrears.length?arrears.map(student=>{const due=outstandingAmount(student),pct=student.fee?Math.round(student.paid/student.fee*100):100;return`<div class="arrears-row">${studentCell(student)}<div class="arrears-money"><span>${money(due)} due</span><small>${pct}% paid · ${money(student.fee)} fee</small></div><button class="mini-button" data-arrears-pdf="${esc(student.id)}">PDF</button></div>`}).join(""):`<div class="empty">No outstanding balances in this scope</div>`
}
