$("#loginForm").addEventListener("submit",e=>{e.preventDefault();if($("#loginPin").value===loginPin){requestSystemFullscreen();unlockSystem();$("#loginError").textContent="";toast(`Welcome, ${profile.name}`)}else{$("#loginError").textContent="Incorrect PIN. Please try again.";$("#loginPin").select()}});
$("#profileForm").addEventListener("submit",e=>{e.preventDefault();profile={name:$("#profileName").value.trim(),role:$("#profileRole").value.trim(),email:$("#profileEmail").value.trim(),phone:$("#profilePhone").value.trim()};localStorage.setItem(STORAGE.profile,JSON.stringify(profile));renderProfile();toast("Profile updated successfully")});
$("#pinForm").addEventListener("submit",e=>{e.preventDefault();const current=$("#currentPin").value,newValue=$("#newPin").value,confirmValue=$("#confirmPin").value;if(current!==loginPin)return toast("Current PIN is incorrect");if(!/^[0-9]{4,8}$/.test(newValue))return toast("PIN must contain 4 to 8 numbers");if(newValue!==confirmValue)return toast("New PIN confirmation does not match");loginPin=newValue;localStorage.setItem(STORAGE.pin,loginPin);$("#loginHint").hidden=true;$("#pinForm").reset();toast("Login PIN updated successfully")});
$("#paymentForm").addEventListener("submit",e=>{e.preventDefault();const s=students.find(x=>x.id===$("#paymentStudentId").value),n=Number($("#newPayment").value);if(n>s.fee-s.paid)return toast("Payment exceeds the outstanding balance");s.paid+=n;persist();closeModals();renderAll();const receipt=showReceipt(s,n);shareReceiptViaWhatsApp(receipt,true);toast("Payment recorded and receipt generated")});
function exportCSV(name,rows){const csv=rows.map(r=>r.map(v=>`"${String(v).replaceAll('"','""')}"`).join(",")).join("\n"),a=document.createElement("a");a.href=URL.createObjectURL(new Blob([csv],{type:"text/csv"}));a.download=name;a.click();URL.revokeObjectURL(a.href)}
function downloadJSON(name,data){const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:"application/json"}));a.download=name;a.click();URL.revokeObjectURL(a.href)}
function fullBackupData(){return{format:"ENP_FULL_BACKUP",version:1,system:"E nena Piyasa Management System",exportedAt:new Date().toISOString(),data:{students,attendance,receipts,examResults,finances,profile,loginPin,theme:document.documentElement.dataset.theme||"light"}}}
function restoreFullBackup(backup){if(backup?.format!=="ENP_FULL_BACKUP"||!backup.data||!Array.isArray(backup.data.students)||typeof backup.data.attendance!=="object"||!Array.isArray(backup.data.receipts))throw new Error("Invalid E nena Piyasa full backup file");students=backup.data.students;attendance=backup.data.attendance;receipts=backup.data.receipts;examResults=backup.data.examResults||{};finances=backup.data.finances||{};profile=backup.data.profile||{name:"Administrator",role:"Center Admin",email:"",phone:""};loginPin=/^[0-9]{4,8}$/.test(backup.data.loginPin||"")?backup.data.loginPin:"1234";draftAttendance={};localStorage.setItem(STORAGE.profile,JSON.stringify(profile));localStorage.setItem(STORAGE.pin,loginPin);persist();setTheme(backup.data.theme==="dark"?"dark":"light");renderProfile();renderAll()}
$("#exportStudents").onclick=()=>exportCSV("enp-students.csv",[["ID","Name","Phone","Guardian","Course","Group","Joined","Fee","Paid","Status"],...filteredStudents().map(s=>[s.id,s.name,s.phone,s.guardian,s.course,s.group,s.joined,s.fee,s.paid,paymentStatus(s)])]);
$("#exportPayments").onclick=()=>exportCSV("enp-payments.csv",[["ID","Name","Course","Fee","Paid","Outstanding","Status"],...filteredPayments().map(s=>[s.id,s.name,s.course,s.fee,s.paid,s.fee-s.paid,paymentStatus(s)])]);
$("#downloadAllArrearsPdf").onclick=downloadAllArrearsPDF;
$("#exportAttendance").onclick=()=>{if(!lastAttendanceReport)return;const r=lastAttendanceReport;exportCSV(`enp-attendance-${r.date}.csv`,[["Date","Day","Status","Student ID","Student Name","Course","Phone","Guardian Phone"],...r.assigned.map(s=>[r.date,r.day,attendance[r.date][s.id],s.id,s.name,s.course,s.phone,s.guardian])])};
$("#downloadAttendanceBackup").onclick=()=>downloadJSON(`enp-attendance-backup-${today()}.json`,{system:"E nena Piyasa Management System",exportedAt:new Date().toISOString(),students,attendance});
$("#downloadKidAttendanceBackup").onclick=$("#downloadAttendanceBackup").onclick;
$("#historyBackup").onclick=$("#downloadAttendanceBackup").onclick;
$("#exportFullBackup").onclick=()=>{downloadJSON(`enp-full-backup-${today()}.json`,fullBackupData());toast("Full system backup exported")};
$("#importFullBackup").onclick=()=>$("#backupFileInput").click();
$("#backupFileInput").addEventListener("change",async e=>{const file=e.target.files[0];if(!file)return;try{const backup=JSON.parse(await file.text());if(!confirm(`Restore backup from ${backup.exportedAt?new Date(backup.exportedAt).toLocaleString():"this file"}? Current data will be replaced.`))return;restoreFullBackup(backup);toast("Full backup restored successfully")}catch(error){toast(error.message||"Unable to import backup")}finally{e.target.value=""}});
$("#fullSystemReset").onclick=()=>{if(!confirm("Full Reset will permanently delete every student, register and receipt. Continue?"))return;if(prompt('Type RESET to confirm the full system reset:')!=="RESET")return toast("Full reset cancelled");students=[];attendance={};receipts=[];examResults={};finances={};draftAttendance={};profile={name:"Administrator",role:"Center Admin",email:"",phone:""};loginPin="1234";Object.values(STORAGE).forEach(key=>localStorage.removeItem(key));localStorage.setItem(STORAGE.profile,JSON.stringify(profile));localStorage.setItem(STORAGE.pin,loginPin);persist();setTheme("light");renderProfile();renderAll();go("dashboard");toast("System fully reset. Default PIN is 1234")};
$("#printReceipt").onclick=downloadReceiptPDF;
$("#whatsappReceipt").onclick=()=>shareReceiptViaWhatsApp(lastReceipt);
$("#receiptLookupForm").addEventListener("submit",e=>{e.preventDefault();const value=$("#receiptLookupInput").value.trim(),receipt=receipts.find(r=>r.number.toLowerCase()===value.toLowerCase());if(receipt){$("#receiptLookupMessage").className="lookup-message success";$("#receiptLookupMessage").textContent=`Verified: ${receipt.student.name} · ${money(receipt.payment)}`;openReceipt(receipt)}else{$("#receiptLookupMessage").className="lookup-message error";$("#receiptLookupMessage").textContent="Receipt not found. Check the Receipt ID and try again."}});
$("#examStudentIdLookup").addEventListener("input",renderExamSuggestions);$("#examStudentIdLookup").addEventListener("focus",renderExamSuggestions);$("#examIdLookupForm").addEventListener("submit",e=>{e.preventDefault();const value=$("#examStudentIdLookup").value.trim().toLowerCase(),matches=matchingExamStudents(value),student=students.find(s=>s.course==="ICTT"&&(s.id.toLowerCase()===value||s.name.toLowerCase()===value||examIdEnding(s.id).toLowerCase()===value))||(matches.length===1?matches[0]:null);if(student)selectExamStudent(student);else{$("#examLookupMessage").className="error";$("#examLookupMessage").textContent=matches.length?"Select a student from the suggestions":"No matching ICTT students found";toast($("#examLookupMessage").textContent)}});$("#examStudentSelect").addEventListener("change",()=>{const student=students.find(s=>s.id===$("#examStudentSelect").value);$("#examStudentIdLookup").value=student?`${student.name} · ${student.id}`:"";$("#examLookupMessage").textContent="";renderExamResults()});$("#downloadSelectedProgress").onclick=()=>{const id=$("#examStudentSelect").value;if(!id)return toast("Select a student first");renderProgressPreview(id)};$("#downloadProgressPdf").onclick=()=>downloadProgressReport();$("#shareProgressWhatsapp").onclick=()=>shareProgressReportViaWhatsApp();$("#saveExamResults").onclick=()=>{const id=$("#examStudentSelect").value;if(!id)return toast("Select an ICTT student");ensureExamResult(id).updatedAt=new Date().toISOString();persist();renderExamResults();toast("ICTT exam results saved successfully")};
$("#incomeYear").addEventListener("change",renderIncomeSummary);$("#downloadIncomePDF").onclick=downloadIncomePDF;$("#incomeSummaryTable").addEventListener("input",e=>{if(!e.target.dataset.financeField)return;const year=$("#incomeYear").value||"2026",rows=ensureFinanceYear(year),month=Number(e.target.dataset.financeMonth);rows[month][e.target.dataset.financeField]=Math.max(0,Number(e.target.value||0));persist();refreshFinanceTotals(year,month)});
$("#saveAttendance").onclick=()=>{const date=$("#attendanceDate").value,day=classDayForDate(date),marks=draftAttendance[date]||{},assigned=students.filter(s=>s.course!=="Kid Course"&&s.group===day),unmarked=assigned.filter(s=>!marks[s.id]);if(!assigned.length)return toast("No regular course students assigned to this date");if(unmarked.length)return toast(`Mark Present or Absent for all ${unmarked.length} remaining students`);attendance[date]={...marks};persist();renderAll();showAttendanceResult(date);toast("Day register completed and saved")};
$("#saveKidAttendance").onclick=()=>{const date=$("#kidAttendanceDate").value,key=kidRecordKey(date),marks=draftAttendance[key]||{},assigned=students.filter(s=>s.course==="Kid Course"),unmarked=assigned.filter(s=>!marks[s.id]);if(!assigned.length)return toast("No Kid Course students registered");if(unmarked.length)return toast(`Mark Present or Absent for all ${unmarked.length} remaining kids`);marks.__kids=assigned.map(s=>s.id);attendance[key]={...marks};persist();renderAll();showAttendanceResult(key);toast("Kid Course register completed and saved")};
$("#markAllPresent").onclick=()=>{const d=$("#attendanceDate").value,day=classDayForDate(d);students.filter(s=>s.course!=="Kid Course"&&s.group===day).forEach(s=>draftAttendance[d][s.id]="present");renderAttendance()};
$("#markAllKidsPresent").onclick=()=>{const key=kidRecordKey($("#kidAttendanceDate").value);students.filter(s=>s.course==="Kid Course").forEach(s=>draftAttendance[key][s.id]="present");renderKidAttendance()};
$("#clearAttendance").onclick=()=>{draftAttendance[$("#attendanceDate").value]={};renderAttendance()};
$("#clearKidAttendance").onclick=()=>{draftAttendance[kidRecordKey($("#kidAttendanceDate").value)]={__kids:students.filter(s=>s.course==="Kid Course").map(s=>s.id)};renderKidAttendance()};
$("#addStudent").onclick=()=>openStudent();$("#quickAdd").onclick=()=>openStudent();$("#menuButton").onclick=()=>toggleSidebar();$("#sidebarBackdrop").onclick=()=>toggleSidebar(false);
$("#themeToggle").onclick=()=>setTheme(document.documentElement.dataset.theme==="dark"?"light":"dark");
$("#studentCourse").addEventListener("change",()=>{syncCourseDay();suggestStudentId()});$("#joinedDate").addEventListener("change",()=>suggestStudentId());$("#studentId").addEventListener("input",()=>$("#studentId").dataset.auto="false");
$("#profileButton").onclick=e=>{e.stopPropagation();$("#profileMenu").classList.toggle("open")};$("#openProfile").onclick=openProfile;$("#lockSystem").onclick=lockSystem;$("#logoutSystem").onclick=lockSystem;document.addEventListener("click",e=>{if(!e.target.closest(".profile-wrap"))$("#profileMenu").classList.remove("open");if(!e.target.closest(".exam-search-wrap")){$("#examStudentSuggestions").classList.remove("open");$("#examStudentIdLookup").setAttribute("aria-expanded","false")}});
$$(".nav-item").forEach(n=>n.onclick=()=>{$$(".course-nav-item").forEach(x=>x.classList.remove("active"));if(n.dataset.view==="students")$("#courseFilter").value="all";go(n.dataset.view)});["studentSearch","courseFilter","groupFilter","statusFilter"].forEach(id=>$(`#${id}`).addEventListener("input",()=>{$$(".course-nav-item").forEach(x=>x.classList.toggle("active",$("#courseFilter").value===x.dataset.courseNav));renderStudents()}));["attendanceDate","attendanceSearch"].forEach(id=>$(`#${id}`).addEventListener("input",renderAttendance));["kidAttendanceDate","kidAttendanceSearch"].forEach(id=>$(`#${id}`).addEventListener("input",renderKidAttendance));["paymentSearch","paymentFilter"].forEach(id=>$(`#${id}`).addEventListener("input",renderPayments));["receiptSearch","receiptCourseFilter","receiptStatusFilter"].forEach(id=>$(`#${id}`).addEventListener("input",renderReceipts));["analyticsPeriod","analyticsCourse"].forEach(id=>$(`#${id}`).addEventListener("change",renderAnalytics));$("#historySearch").addEventListener("input",renderHistory);$("#lowAttendanceSearch").addEventListener("input",renderBackup);
let touchStartX=0,touchStartY=0;document.addEventListener("touchstart",e=>{touchStartX=e.changedTouches[0].clientX;touchStartY=e.changedTouches[0].clientY},{passive:true});document.addEventListener("touchend",e=>{if(innerWidth>760)return;const dx=e.changedTouches[0].clientX-touchStartX,dy=Math.abs(e.changedTouches[0].clientY-touchStartY);if(dy>80||Math.abs(dx)<70)return;if(dx>0&&touchStartX<35)toggleSidebar(true);if(dx<0&&$("#sidebar").classList.contains("open"))toggleSidebar(false)},{passive:true});window.addEventListener("resize",()=>{if(innerWidth>760)toggleSidebar(false)});
setTheme(localStorage.getItem(STORAGE.theme)||"light");renderProfile();$("#loginHint").hidden=Boolean(localStorage.getItem(STORAGE.pin));if(sessionStorage.getItem("enp_unlocked")==="1")unlockSystem();else lockSystem();$("#todayLabel").textContent=new Intl.DateTimeFormat("en-GB",{weekday:"short",day:"2-digit",month:"short",year:"numeric"}).format(new Date());$("#attendanceDate").value=today();$("#kidAttendanceDate").value=today();renderAll();
